# REQ-007 — DND deactivation must NOT resurface anything
# ---------------------------------------------------------------------------

def test_dnd_deactivation_does_not_fire_retroactive_push():
    """REQ-007: DND end → no retroactive push for the silenced backlog."""
    member = make_member("m1")
    channel = make_channel()
    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    # Accumulate 3 silenced mentions during DND.
    for i in range(3):
        event = make_event_for("m1", channel=channel)
        event.id = f"evt-during-dnd-{i}"
        DispatchMentionNotification(
            member=member, event=event,
            surfaces=(push, banner, sound, badge),
            dnd=DNDState(manual_on=True, schedule_window=None, muted_channels=set()),
        )
    # Now DND ends.
    OnDNDDeactivated(member=member, surfaces=(push, banner, sound, badge))

    assert push.total_fire_count() == 0, "retroactive push fired after DND end"


