def test_dnd_deactivation_preserves_existing_unread_badge_and_count():
    """REQ-007: DND end → badge & unread count remain (no zeroing, no re-fire)."""
    member = make_member("m1")
    channel = make_channel()
    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    for i in range(3):
        event = make_event_for("m1", channel=channel)
        event.id = f"evt-during-dnd-{i}"
        DispatchMentionNotification(
            member=member, event=event,
            surfaces=(push, banner, sound, badge),
            dnd=DNDState(manual_on=True, schedule_window=None, muted_channels=set()),
        )

    count_before = badge.unread_mention_count_for(member)
    assert count_before == 3, "DND silencing should have accumulated 3 silent badge increments"

    OnDNDDeactivated(member=member, surfaces=(push, banner, sound, badge))

    count_after = badge.unread_mention_count_for(member)
    assert count_after == count_before, "DND end zeroed or modified the badge — must be preserved"


# ---------------------------------------------------------------------------
# PBT — thread-participation boundary (REQ-001 constraint)
# ---------------------------------------------------------------------------

@settings(max_examples=500, deadline=None)
@given(
    st.lists(st.sampled_from(["m0", "m1", "m2", "m3"]), min_size=0, max_size=4, unique=True),
    st.sampled_from(["m0", "m1", "m2", "m3"]),
)
def test_in_thread_participation_boundary_only_prior_posters_receive_mentions(participants, mentioned_id):
    """Property: boundary (REQ-001). In a thread, mention is delivered iff
    mentioned_id has previously posted (is in `participants`)."""
    from src.notifications.resolve import ResolveMentionRecipients

    parent = make_channel("c1", member_ids=("m0", "m1", "m2", "m3"))
    thread = make_channel("t1", member_ids=("m0", "m1", "m2", "m3"), is_thread=True, parent=parent)
    thread.thread_participants = set(participants)

    message = Message(
        id="msg1", channel=thread, author_id="m99",
        mention_ids=[mentioned_id], mention_kind=MentionKind.INDIVIDUAL,
    )

    recipients = ResolveMentionRecipients(message)
    delivered = mentioned_id in {r.member_id for r in recipients}

    # Boundary: delivered iff prior participation. No "in between" state.
    assert delivered == (mentioned_id in participants), (
        f"thread boundary violated: participants={participants} mentioned={mentioned_id} delivered={delivered}"
    )


# ---------------------------------------------------------------------------
# PBT — DND lifecycle state machine (REQ-002 + REQ-007)
# ---------------------------------------------------------------------------
# States: DND_OFF → DND_ON via manual_on=True OR enter_schedule_window OR
# mute_channel; DND_ON → DND_OFF via manual_off AND outside_window AND
# unmute. The well-formedness invariants:
#   - while DND_ON: push/banner/sound counts must NOT increase on mention
#   - while DND_OFF: push/banner/sound counts MAY increase on mention
#   - transition DND_ON → DND_OFF: no retroactive fire (counts unchanged
#     at the transition step itself)
#   - badge count is monotonic non-decreasing across all rules


class DNDLifecycleStateMachine(RuleBasedStateMachine):
    """Property: state_machine (REQ-002 + REQ-007). DND lifecycle well-formedness."""

    def __init__(self):
        super().__init__()
        self.member = Member(id="m_target")
        self.channel = make_channel("c1", member_ids=("m_target", "m99"))
        self.push = PushSurface()
        self.banner = InAppBannerSurface()
        self.sound = SoundSurface()
        self.badge = UnreadBadgeSurface()
        self.surfaces = (self.push, self.banner, self.sound, self.badge)
        self.dnd = DNDState(manual_on=False, schedule_window=None, muted_channels=set())
        self.event_counter = 0
        self._badge_history = [self.badge.unread_mention_count_for(self.member)]

    def _current_dnd_active(self):
        # Mirrors the implementer's expected "is_dnd_for" predicate.
        return (
            self.dnd.manual_on
            or self.dnd.schedule_window is not None
            or self.channel.id in self.dnd.muted_channels
        )

    @rule()
    def manual_toggle_on(self):
        self.dnd = DNDState(
            manual_on=True,
            schedule_window=self.dnd.schedule_window,
            muted_channels=self.dnd.muted_channels,
        )

    @rule()
    def manual_toggle_off(self):
        was_on = self._current_dnd_active()
        self.dnd = DNDState(
            manual_on=False,
            schedule_window=self.dnd.schedule_window,
            muted_channels=self.dnd.muted_channels,
        )
        if was_on and not self._current_dnd_active():
            # Transition DND_ON → DND_OFF
            push_before = self.push.total_fire_count()
            banner_before = self.banner.total_fire_count()
            sound_before = self.sound.total_fire_count()
            OnDNDDeactivated(member=self.member, surfaces=self.surfaces)
            # No resurfacing at the transition itself (REQ-007).
            assert self.push.total_fire_count() == push_before
            assert self.banner.total_fire_count() == banner_before
            assert self.sound.total_fire_count() == sound_before

    @rule()
    def enter_scheduled_window(self):
        self.dnd = DNDState(
            manual_on=self.dnd.manual_on,
            schedule_window=(time(0, 0), time(23, 59)),
            muted_channels=self.dnd.muted_channels,
        )

    @rule()
    def leave_scheduled_window(self):
        was_on = self._current_dnd_active()
        self.dnd = DNDState(
            manual_on=self.dnd.manual_on,
            schedule_window=None,
            muted_channels=self.dnd.muted_channels,
        )
        if was_on and not self._current_dnd_active():
            push_before = self.push.total_fire_count()
            OnDNDDeactivated(member=self.member, surfaces=self.surfaces)
            assert self.push.total_fire_count() == push_before

    @rule()
    def mute_current_channel(self):
        self.dnd = DNDState(
            manual_on=self.dnd.manual_on,
            schedule_window=self.dnd.schedule_window,
            muted_channels=self.dnd.muted_channels | {self.channel.id},
        )

    @rule()
    def unmute_current_channel(self):
        was_on = self._current_dnd_active()
        new_muted = self.dnd.muted_channels - {self.channel.id}
        self.dnd = DNDState(
            manual_on=self.dnd.manual_on,
            schedule_window=self.dnd.schedule_window,
            muted_channels=new_muted,
        )
        if was_on and not self._current_dnd_active():
            push_before = self.push.total_fire_count()
            OnDNDDeactivated(member=self.member, surfaces=self.surfaces)
            assert self.push.total_fire_count() == push_before

    @rule()
    def receive_mention(self):
        push_before = self.push.total_fire_count()
        banner_before = self.banner.total_fire_count()
        sound_before = self.sound.total_fire_count()
        badge_before = self.badge.unread_mention_count_for(self.member)

        event = make_event_for("m_target", channel=self.channel)
        event.id = f"evt-sm-{self.event_counter}"
        self.event_counter += 1

        DispatchMentionNotification(
            member=self.member, event=event,
            surfaces=self.surfaces, dnd=self.dnd,
        )

        push_after = self.push.total_fire_count()
        banner_after = self.banner.total_fire_count()
        sound_after = self.sound.total_fire_count()
        badge_after = self.badge.unread_mention_count_for(self.member)

        if self._current_dnd_active():
            # Silence: no push/banner/sound increment.
            assert push_after == push_before, "push fired while DND active"
            assert banner_after == banner_before, "banner fired while DND active"
            assert sound_after == sound_before, "sound fired while DND active"
            # Badge still increments silently.
            assert badge_after == badge_before + 1, "badge did not increment under DND"
        else:
            # No DND → all surfaces should fire.
            assert push_after == push_before + 1, "push did not fire while DND inactive"
            assert badge_after == badge_before + 1, "badge did not increment while DND inactive"

    @invariant()
    def badge_is_monotonic(self):
        cur = self.badge.unread_mention_count_for(self.member)
        prev = self._badge_history[-1]
        assert cur >= prev, f"badge decreased: {prev} → {cur}"
        self._badge_history.append(cur)

    @invariant()
    def dnd_state_is_well_formed(self):
        # manual_on is bool; schedule_window is None or (time, time);
        # muted_channels is a set of str.
        assert isinstance(self.dnd.manual_on, bool)
        assert self.dnd.schedule_window is None or (
            isinstance(self.dnd.schedule_window, tuple)
            and len(self.dnd.schedule_window) == 2
        )
        assert isinstance(self.dnd.muted_channels, set)


TestDNDLifecycleStateMachine = DNDLifecycleStateMachine.TestCase
TestDNDLifecycleStateMachine.settings = settings(max_examples=500, deadline=None, stateful_step_count=20)

# Wrapper test so the bare-string name in done_when.yaml maps to a discoverable test:
def test_dnd_lifecycle_state_machine_is_well_formed():
    """Property: state_machine (REQ-002, REQ-007). Wraps DNDLifecycleStateMachine."""
    TestDNDLifecycleStateMachine().runTest()
